#ifndef HYSTERESIS_H
#define HYSTERESIS_H
#include <Arduino.h>

class Hysteresis {
public:
    Hysteresis(float highThreshold, float lowThreshold);
    bool update(float value);
    bool getState() const;
    void setThresholds(float high, float low);
private:
    float _high, _low;
    bool _state;
};

#endif

firmware_template.source:
#include "hysteresis.h"

Hysteresis::Hysteresis(float highThreshold, float lowThreshold)
    : _high(highThreshold), _low(lowThreshold), _state(false) {}

bool Hysteresis::update(float value) {
    if (_state && value < _low) _state = false;
    else if (!_state && value > _high) _state = true;
    return _state;
}

bool Hysteresis::getState() const { return _state; }

void Hysteresis::setThresholds(float high, float low) {
    _high = high; _low = low;
}
